queryParams = {"roleID":self.session.custom.selectedRoleID}
queryPath = 'Project_VECV/Role/Role_Screens/Get_ScreenData'
result = system.db.runNamedQuery(queryPath,queryParams)

pyData = system.dataset.toPyDataSet(result)
optionList = []
for data in pyData:
	dict = {
		"instanceStyle": {
		  "classes": ""
		},
		"instancePosition": {}
	  }
	dict["fieldName"] = data["Screen name"]
	dict["Id"] = data["FormID"]
	dict["moduleId"] = data["ModuleID"]
	if data["Edit permission"] == 1:
		dict["IsSelected"] = True
	else:
		dict["IsSelected"] =False
	optionList.append(dict)
self.view.custom.screenData = optionList

